#include<bits/stdc++.h>
using namespace std;
int q[1000010],dp[1000010],n,d[1000010];
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&d[i]);
    }
    int q;
    scanf("%d",&q);
    while(q--)
    {
        int k;
        scanf("%d",&k);
        for(int i=1;i<=n;i++)
        {
            dp[i]=0;
        }
        deque<int> q;
        q.push_back(1);
        for(int i=2;i<=n;i++)
        {
            while(!q.empty()&&q.front()<i-k)
            {
                q.pop_front();
            }
            dp[i]=dp[q.front()]+(d[i]>=d[q.front()]);
            while(!q.empty()&&((dp[i]<dp[q.back()])||(dp[i]==dp[q.back()]&&d[i]>d[q.back()])))
            {
                q.pop_back();
            }
            q.push_back(i);
        }
        printf("%d\n",dp[n]);
    }
    return 0;
}
